prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "2d887704") || CONTAINS(LCASE(STR(?normId)), "2d887704"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?sourceRef ?targetRef ?messageRef ?msgName WHERE {
  ?msgFlow a bboExt:MessageFlow .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }
  OPTIONAL { 
    ?msg a bboExt:Message .
    FILTER(STRENDS(STR(?msg), ?messageRef))
    ?msg bbo:name ?msgName .
  }
  ?choreo a bboExt:Choreography .
  ?msgFlow tai:belongsTo ?choreo .
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?sourceRef ?targetRef ?messageRef ?msgName WHERE {
  ?msgFlow a bboExt:MessageFlow .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }
  OPTIONAL { 
    ?msg a bboExt:Message .
    FILTER(STRENDS(STR(?msg), ?messageRef))
    ?msg bbo:name ?msgName .
  }
  ?task bbo:name "Get client to add the relevant cost centre" .
  FILTER(?sourceRef = "sid-4F47FE5C-11B4-459C-BF80-F9D6BB03E80C" || ?targetRef = "sid-4F47FE5C-11B4-459C-BF80-F9D6BB03E80C")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edgeType ?edge ?otherNode ?otherName WHERE {
  ?task bbo:name "Get client to add the relevant cost centre" .
  {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_sourceRef ?task .
    ?edge bbo:has_targetRef ?otherNode .
    OPTIONAL { ?otherNode bbo:name ?otherName . }
    BIND("outgoing" AS ?edgeType)
  }
  UNION
  {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_targetRef ?task .
    ?edge bbo:has_sourceRef ?otherNode .
    OPTIONAL { ?otherNode bbo:name ?otherName . }
    BIND("incoming" AS ?edgeType)
  }
}
LIMIT 25
